"use client";

import React, { createContext, useContext, useEffect, useMemo, useState } from "react";
import { ActivityLog, ActivityCategory, ActivityGroup, ActivityModule } from "../types";
import { listActivities } from "@/lib/client/services/activity.service";

interface ActivityContextType {
  activities: ActivityLog[];
  searchQuery: string;
  setSearchQuery: (query: string) => void;
  selectedCategory: "All" | ActivityModule;
  setSelectedCategory: (category: "All" | ActivityModule) => void;
  groupedActivities: ActivityGroup[];
  loading: boolean;
  error: string | null;
}

const ActivityContext = createContext<ActivityContextType | undefined>(undefined);

export function ActivityProvider({ children }: { children: React.ReactNode }) {
  const [allActivities, setAllActivities] = useState<ActivityLog[]>([]);
  const [searchQuery, setSearchQuery] = useState("");
  const [selectedCategory, setSelectedCategory] = useState<"All" | ActivityModule>("All");
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    let cancelled = false;

    async function load() {
      setLoading(true);
      setError(null);
      try {
        const items = await listActivities();
        if (!cancelled) setAllActivities(items as ActivityLog[]);
      } catch (err) {
        if (!cancelled) setError(err instanceof Error ? err.message : "Failed to load activity log");
      } finally {
        if (!cancelled) setLoading(false);
      }
    }

    load();
    return () => {
      cancelled = true;
    };
  }, []);

  const filteredActivities = useMemo(() => {
    return allActivities.filter(a => {
      const matchesSearch = a.entityName.toLowerCase().includes(searchQuery.toLowerCase()) || 
                            a.description?.toLowerCase().includes(searchQuery.toLowerCase()) ||
                            a.user.name.toLowerCase().includes(searchQuery.toLowerCase());
      const matchesModule = selectedCategory === "All" || a.module === selectedCategory;
      return matchesSearch && matchesModule;
    });
  }, [allActivities, searchQuery, selectedCategory]);

  const groupedActivities = useMemo(() => {
    const groups: Record<string, ActivityLog[]> = {};

    filteredActivities.forEach(activity => {
      const date = new Date(activity.timestamp).toLocaleDateString("en-US", {
        weekday: "long",
        month: "long",
        day: "numeric",
        year: "numeric"
      });
      if (!groups[date]) groups[date] = [];
      groups[date].push(activity);
    });

    return Object.entries(groups).map(([date, activities]) => ({
      date,
      activities: activities.sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime())
    }));
  }, [filteredActivities]);

  const value = {
    activities: filteredActivities,
    searchQuery,
    setSearchQuery,
    selectedCategory,
    setSelectedCategory,
    groupedActivities,
    loading,
    error
  };

  return <ActivityContext.Provider value={value}>{children}</ActivityContext.Provider>;
}

export function useActivity() {
  const context = useContext(ActivityContext);
  if (!context) throw new Error("useActivity must be used within ActivityProvider");
  return context;
}

"use client";

import React, { useState } from "react";
import {
  ChevronDown,
  Calendar as CalendarIcon
} from "lucide-react";
import { ActivityProvider, useActivity } from "./context/ActivityContext";
import ActivityTimeline from "./components/ActivityTimeline";
import ActivityDetailsDrawer from "./components/ActivityDetailsDrawer";
import { ActivityModule } from "./types";
import ModuleHeader from "../components/shared/ModuleHeader";
import ModuleTabs from "../components/shared/ModuleTabs";
import SearchInput from "../components/shared/SearchInput";
import ExportButton from "../components/shared/ExportButton";
import DateRangePicker from "../components/shared/DateRangePicker";

function ActivityContent() {
  const {
    activities,
    searchQuery,
    setSearchQuery,
    selectedCategory,
    setSelectedCategory
  } = useActivity();

  const [selectedActivityId, setSelectedActivityId] = useState<string | null>(null);
  const [dateRange, setDateRange] = useState("Last 7 Days");

  const modules = [
    { id: "All", label: "All Activity" },
    { id: "TASKS", label: "Tasks" },
    { id: "MARKETING", label: "Marketing" },
    { id: "TEAM", label: "Team" },
    { id: "FINANCE", label: "Finance" },
    { id: "DOCUMENTS", label: "Documents" },
    { id: "SYSTEM", label: "System" }
  ];

  return (
    <div className="flex-1 flex flex-col bg-[#fef8f8] overflow-hidden">

      <ModuleHeader
        title="Activity Log"
        count={activities.length}
        className="!bg-[#f9f5f5] border-black/[0.06]"
        rightContent={(
          <SearchInput
            value={searchQuery}
            onChange={setSearchQuery}
            placeholder="Search history..."
            width={180}
          />
        )}
      />

      <ModuleTabs
        tabs={modules}
        activeTab={selectedCategory}
        onTabChange={(id) => setSelectedCategory(id as any)}
        background="bg-[#f9f5f5]"
        className="border-black/[0.06]"
        rightContent={(
          <div className="flex items-center gap-3 px-6">
            <DateRangePicker value={dateRange} onChange={setDateRange} />
            <ExportButton label="Export" />
          </div>
        )}
      />

      {/* ── Operational Log Stream ── */}
      <main className="flex-1 overflow-y-auto custom-scrollbar">
        <ActivityTimeline onSelect={id => setSelectedActivityId(id)} />
      </main>

      {/* Details Drawer */}
      {selectedActivityId && (
        <ActivityDetailsDrawer
          activityId={selectedActivityId}
          onClose={() => setSelectedActivityId(null)}
        />
      )}
    </div>
  );
}

export default function ActivityPage() {
  return (
    <ActivityProvider>
      <ActivityContent />
    </ActivityProvider>
  );
}

export type ActivityCategory = "INFO" | "UPDATE" | "WARNING" | "AUTOMATION" | "SECURITY";
export type ActivityModule = "TASKS" | "MARKETING" | "TEAM" | "FINANCE" | "DOCUMENTS" | "SYSTEM" | "SALES" | "CAMPAIGNS" | "FLOWS" | "GOALS";
export type ActionType = "Created" | "Updated" | "Deleted" | "Completed" | "Signed" | "Triggered" | "Invited" | "Uploaded" | "Connected" | "Published" | "Archived" | "Approved" | "Sent";

export interface ActivityLog {
  id: string;
  category: ActivityCategory;
  module: ActivityModule;
  action: ActionType;
  entityName: string;
  entityType: string;
  entityId: string;
  user: {
    id: string;
    name: string;
    avatar?: string;
    role: string;
  };
  timestamp: string;
  metadata?: Record<string, any>;
  description?: string;
}

export interface ActivityGroup {
  date: string;
  activities: ActivityLog[];
}

