                  <div className={`h-1 w-6 rounded-full ${step >= 2 ? "bg-primary" : "bg-black/10"}`} />
                  <div className={`h-1 w-6 rounded-full ${step >= 3 ? "bg-primary" : "bg-black/10"}`} />
