"use client";

import React, { useMemo, useState } from "react";
import { Activity, CalendarDays, CheckCircle2, MessageSquare, Trash2, Inbox, ChevronRight, User } from "lucide-react";
import { useCampaigns } from "../context/CampaignsContext";
import type { Campaign, CampaignStatus } from "../types";
import { Table, TableHeader, TableBody, TableRow, TableHead, TableCell } from "../../components/ui/Table";
import Badge from "../../components/ui/Badge";
import EmptyState from "../../components/ui/EmptyState";
import Button from "../../components/ui/Button";
import SelectionBar from "../../components/shared/SelectionBar";
import ConfirmationModal from "../../components/shared/ConfirmationModal";

interface Props {
  searchQuery: string;
  filterMode: string;
  onSelectCampaign: (id: string) => void;
}

function progressFor(campaign: Campaign) {
  if (!campaign.goals.length) return 0;
  return Math.round((campaign.goals.filter(goal => goal.isCompleted).length / campaign.goals.length) * 100);
}

function initials(name: string) {
  return name.split(" ").map(part => part[0]).join("").slice(0, 2).toUpperCase();
}

export default function CampaignList({ searchQuery, filterMode, onSelectCampaign }: Props) {
  const { campaigns, deleteCampaigns } = useCampaigns();
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);
  const [campaignToDelete, setCampaignToDelete] = useState<string | null>(null);

  const filteredCampaigns = useMemo(() => {
    const q = searchQuery.toLowerCase();
    return campaigns.filter(campaign => {
      const matchesSearch =
        campaign.name.toLowerCase().includes(q) ||
        campaign.owner.toLowerCase().includes(q) ||
        campaign.channel.toLowerCase().includes(q);

      if (filterMode === "active") return matchesSearch && campaign.status === "Active";
      if (filterMode === "planning") return matchesSearch && campaign.status === "Planning";
      if (filterMode === "paused") return matchesSearch && campaign.status === "Paused";
      return matchesSearch;
    });
  }, [campaigns, filterMode, searchQuery]);

  const toggleAll = () => {
    if (selectedIds.size === filteredCampaigns.length) {
      setSelectedIds(new Set());
    } else {
      setSelectedIds(new Set(filteredCampaigns.map(c => c.id)));
    }
  };

  const toggleOne = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    const next = new Set(selectedIds);
    if (next.has(id)) next.delete(id); else next.add(id);
    setSelectedIds(next);
  };

  const handleDeleteOne = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    setCampaignToDelete(id);
    setIsDeleteModalOpen(true);
  };

  const handleConfirmDelete = () => {
    if (campaignToDelete) {
      deleteCampaigns([campaignToDelete]);
      setCampaignToDelete(null);
    } else {
      deleteCampaigns(Array.from(selectedIds));
      setSelectedIds(new Set());
    }
    setIsDeleteModalOpen(false);
  };

  const getStatusVariant = (status: CampaignStatus): any => {
    switch (status) {
      case "Active": return "primary";
      case "Planning": return "warning";
      case "Paused": return "neutral";
      case "Completed": return "success";
      default: return "neutral";
    }
  };

  if (!filteredCampaigns.length) {
    return (
      <EmptyState 
        icon={Inbox}
        title="No campaigns found"
        description="Try adjusting your filters or search query."
      />
    );
  }

  return (
    <div className="flex flex-col h-full bg-[#fef8f8] relative">
      <div className="flex-1 overflow-y-auto">
        <Table>
          <TableHeader className="bg-[#f9f5f5] border-b border-black/[0.04] sticky top-0 z-10">
            <TableRow className="bg-[#f9f5f5] border-none hover:bg-[#f9f5f5]">
              <TableHead className="w-12">
                <div className="flex items-center justify-center">
                  <input 
                    type="checkbox" 
                    checked={selectedIds.size > 0 && selectedIds.size === filteredCampaigns.length}
                    onChange={toggleAll}
                    className="w-3.5 h-3.5 rounded-sm border-black/10 accent-black cursor-pointer opacity-60 hover:opacity-100 transition-opacity"
                  />
                </div>
              </TableHead>
              <TableHead className="font-label-caps text-[9px] font-bold text-on-surface-variant opacity-60 uppercase tracking-[0.2em] py-4">Campaign Unit</TableHead>
              <TableHead className="font-label-caps text-[9px] font-bold text-on-surface-variant opacity-60 uppercase tracking-[0.2em] py-4">Status</TableHead>
              <TableHead className="font-label-caps text-[9px] font-bold text-on-surface-variant opacity-60 uppercase tracking-[0.2em] py-4">Fulfillment</TableHead>
              <TableHead className="font-label-caps text-[9px] font-bold text-on-surface-variant opacity-60 uppercase tracking-[0.2em] py-4">Owner</TableHead>
              <TableHead className="font-label-caps text-[9px] font-bold text-on-surface-variant opacity-60 uppercase tracking-[0.2em] py-4 text-right">Schedule</TableHead>
              <TableHead className="w-16"></TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {filteredCampaigns.map((campaign) => {
              const isSelected = selectedIds.has(campaign.id);
              const progress = progressFor(campaign);

              return (
                <TableRow 
                  key={campaign.id}
                  onClick={() => onSelectCampaign(campaign.id)}
                  className={`group transition-colors ${isSelected ? "bg-black/[0.01]" : "bg-[#fef8f8] hover:bg-black/[0.005]"}`}
                >
                  <TableCell onClick={e => e.stopPropagation()}>
                    <div className="flex items-center justify-center">
                      <input 
                        type="checkbox" 
                        checked={isSelected}
                        onChange={(e) => toggleOne(campaign.id, e as any)}
                        className={`w-3.5 h-3.5 rounded-sm border-black/10 accent-black cursor-pointer transition-opacity ${isSelected ? "opacity-100" : "opacity-0 group-hover:opacity-60"}`}
                      />
                    </div>
                  </TableCell>
                  <TableCell>
                    <div className="flex flex-col gap-0.5 py-1">
                      <span className="font-display font-bold text-[13px] text-on-surface tracking-tight group-hover:text-primary transition-colors">
                        {campaign.name}
                      </span>
                      <span className="font-label-caps text-[7px] font-bold text-on-surface-variant opacity-60 uppercase tracking-widest">
                        {campaign.id} • {campaign.channel}
                      </span>
                    </div>
                  </TableCell>
                  <TableCell>
                    <div className="flex">
                       <span className={`px-2 py-0.5 rounded-[4px] font-label-caps text-[8px] font-bold uppercase tracking-widest ${campaign.status === 'Active' ? 'bg-black text-white' : 'bg-black/[0.05] text-on-surface-variant opacity-70'}`}>
                          {campaign.status}
                       </span>
                    </div>
                  </TableCell>
                  <TableCell>
                    <div className="flex items-center gap-4 min-w-[120px]">
                      <div className="flex-1 h-1 rounded-full bg-black/[0.04] overflow-hidden">
                        <div className="h-full bg-black opacity-60 rounded-full transition-all duration-1000" style={{ width: `${progress}%` }} />
                      </div>
                      <span className="font-display text-[11px] font-bold text-on-surface opacity-60 tabular-nums">{progress}%</span>
                    </div>
                  </TableCell>
                  <TableCell>
                    <div className="flex items-center gap-3">
                       <div className="h-6 w-6 rounded-full bg-black/[0.04] border border-black/[0.04] flex items-center justify-center font-display font-bold text-[8px] text-on-surface-variant opacity-60">
                          {initials(campaign.owner)}
                       </div>
                       <span className="font-body-sm text-[12.5px] font-medium text-on-surface opacity-60">{campaign.owner}</span>
                    </div>
                  </TableCell>
                  <TableCell className="text-right">
                    <span className="font-label-caps text-[9px] font-bold text-on-surface-variant opacity-60 uppercase tracking-tight">
                      {new Date(campaign.startDate).toLocaleDateString("en-US", { month: "short", day: "numeric" })} - {new Date(campaign.endDate).toLocaleDateString("en-US", { month: "short", day: "numeric" })}
                    </span>
                  </TableCell>
                  <TableCell className="text-right">
                    <div className="flex items-center justify-end opacity-0 group-hover:opacity-100 transition-all pr-4">
                       <button 
                         className="p-1.5 text-on-surface-variant opacity-60 hover:opacity-100 hover:text-red-500 transition-all"
                         onClick={(e) => handleDeleteOne(e, campaign.id)}
                       >
                         <Trash2 size={13} />
                       </button>
                    </div>
                  </TableCell>
                </TableRow>
              );
            })}
          </TableBody>
        </Table>
      </div>

      <SelectionBar
        count={selectedIds.size}
        onClear={() => setSelectedIds(new Set())}
        onDelete={() => setIsDeleteModalOpen(true)}
        label="campaigns"
      />

      <ConfirmationModal
        isOpen={isDeleteModalOpen}
        onClose={() => { setIsDeleteModalOpen(false); setCampaignToDelete(null); }}
        onConfirm={handleConfirmDelete}
        title={campaignToDelete ? "Delete Campaign" : "Delete Selected Campaigns"}
        description={campaignToDelete
          ? "This will permanently remove this campaign and its linked workspace data."
          : `Delete ${selectedIds.size} selected campaigns? This cannot be undone.`}
      />
    </div>
  );
}

"use client";

import React, { useMemo } from "react";
import { Activity, CalendarDays } from "lucide-react";
import { useCampaigns } from "../context/CampaignsContext";
import type { Campaign } from "../types";

interface Props {
  searchQuery: string;
  filterMode: string;
  onSelectCampaign: (id: string) => void;
}

const DAY_WIDTH = 28;
const LABEL_WIDTH = 300;
const ROW_HEIGHT = 54;

function daysBetween(a: string, b: string) {
  return Math.max(1, Math.round((new Date(b).getTime() - new Date(a).getTime()) / 86_400_000));
}

function dayOffset(from: string, base: string) {
  return Math.round((new Date(from).getTime() - new Date(base).getTime()) / 86_400_000);
}

function progressFor(campaign: Campaign) {
  if (!campaign.goals.length) return 0;
  return Math.round((campaign.goals.filter(goal => goal.isCompleted).length / campaign.goals.length) * 100);
}

function initials(name: string) {
  return name.split(" ").map(part => part[0]).join("").slice(0, 2).toUpperCase();
}

export default function CampaignTimeline({ searchQuery, filterMode, onSelectCampaign }: Props) {
  const { campaigns } = useCampaigns();

  const filtered = useMemo(() => {
    const q = searchQuery.toLowerCase();
    return campaigns.filter(campaign => {
      const matchesSearch =
        campaign.name.toLowerCase().includes(q) ||
        campaign.owner.toLowerCase().includes(q) ||
        campaign.channel.toLowerCase().includes(q) ||
        campaign.tags.some(tag => tag.toLowerCase().includes(q));

      if (filterMode === "active") return matchesSearch && campaign.status === "Active";
      if (filterMode === "planning") return matchesSearch && campaign.status === "Planning";
      if (filterMode === "paused") return matchesSearch && campaign.status === "Paused";
      return matchesSearch;
    });
  }, [campaigns, filterMode, searchQuery]);

  const timeline = useMemo(() => {
    if (!filtered.length) return { baseDate: "", totalDays: 45, rows: [] as Array<{ campaign: Campaign; start: number; width: number }> };

    const dates = filtered.flatMap(campaign => [campaign.startDate, campaign.endDate]);
    const minDate = dates.reduce((a, b) => a < b ? a : b);
    const maxDate = dates.reduce((a, b) => a > b ? a : b);
    const totalDays = Math.max(45, daysBetween(minDate, maxDate) + 8);
    const rows = filtered.map(campaign => {
      const start = Math.max(0, dayOffset(campaign.startDate, minDate));
      const end = Math.max(start + 1, dayOffset(campaign.endDate, minDate));
      return { campaign, start, width: Math.max(2, end - start) };
    });

    return { baseDate: minDate, totalDays, rows };
  }, [filtered]);

  if (!filtered.length || !timeline.baseDate) {
    return (
      <div className="flex flex-col items-center justify-center h-full text-on-surface-variant opacity-60">
        <CalendarDays size={32} className="mb-4 opacity-60" />
        <p className="font-label-caps text-[10px] font-bold uppercase tracking-widest">No active units in schedule</p>
      </div>
    );
  }

  const headers: { offset: number; label: string }[] = [];
  for (let i = 0; i < timeline.totalDays; i += 7) {
    const date = new Date(timeline.baseDate);
    date.setDate(date.getDate() + i);
    headers.push({ offset: i, label: date.toLocaleDateString("en-US", { month: "short", day: "numeric" }) });
  }

  const today = new Date().toISOString().slice(0, 10);
  const todayOffset = dayOffset(today, timeline.baseDate);
  const timelineWidth = timeline.totalDays * DAY_WIDTH;

  return (
    <div className="h-full overflow-auto bg-[#fdf8f8]">
      <div style={{ minWidth: LABEL_WIDTH + timelineWidth + 32 }}>
        <div className="flex sticky top-0 z-20 bg-white border-b border-black/[0.05] shadow-sm">
          <div className="px-8 py-4 shrink-0 border-r border-black/[0.04]" style={{ width: LABEL_WIDTH }}>
            <span className="font-label-caps text-[9px] font-bold uppercase tracking-[0.2em] text-on-surface-variant opacity-60">Operational Unit</span>
          </div>
          <div className="relative flex-1 h-12">
            {headers.map(header => (
              <div key={header.offset} className="absolute top-0 flex h-full items-center" style={{ left: header.offset * DAY_WIDTH, paddingLeft: 8 }}>
                <span className="font-label-caps text-[9px] font-bold text-on-surface-variant opacity-60 uppercase tracking-widest">{header.label}</span>
              </div>
            ))}
            {todayOffset >= 0 && todayOffset <= timeline.totalDays && (
              <div className="absolute top-0 bottom-0 w-px bg-black opacity-60 z-10" style={{ left: todayOffset * DAY_WIDTH }} />
            )}
          </div>
        </div>

        <div className="bg-white">
          {timeline.rows.map(({ campaign, start, width }) => {
            const progress = progressFor(campaign);
            return (
              <div key={campaign.id} className="flex border-b border-black/[0.035]" style={{ height: ROW_HEIGHT }}>
                <button
                  onClick={() => onSelectCampaign(campaign.id)}
                  className="px-8 shrink-0 border-r border-black/[0.04] text-left hover:bg-black/[0.005] transition-colors"
                  style={{ width: LABEL_WIDTH }}
                >
                  <div className="flex items-center gap-4 min-w-0">
                    <div className="h-7 w-7 rounded-full bg-black/[0.03] border border-black/[0.04] flex items-center justify-center font-display font-bold text-[8px] text-on-surface-variant opacity-60">
                      {initials(campaign.owner)}
                    </div>
                    <div className="min-w-0">
                      <h4 className="font-display text-[13px] font-bold text-on-surface truncate tracking-tight">{campaign.name}</h4>
                      <div className="flex items-center gap-2 mt-1">
                         <span className={`px-1.5 py-0.5 rounded-[3px] font-label-caps text-[6px] font-bold uppercase tracking-widest ${campaign.status === 'Active' ? 'bg-black text-white' : 'bg-black/[0.05] text-on-surface-variant opacity-70'}`}>
                            {campaign.status}
                         </span>
                         <span className="font-label-caps text-[7px] font-bold text-on-surface-variant opacity-60 uppercase tracking-widest">{campaign.channel}</span>
                      </div>
                    </div>
                  </div>
                </button>

                <div className="relative flex-1">
                  <div
                    className="absolute top-0 bottom-0 w-px bg-black/[0.02]"
                    style={{ left: todayOffset * DAY_WIDTH }}
                  />
                  <button
                    onClick={() => onSelectCampaign(campaign.id)}
                    className="absolute top-1/2 -translate-y-1/2 rounded-[6px] border border-black/[0.08] bg-white px-3 py-1.5 text-left shadow-sm hover:border-black/30 hover:shadow-md transition-all group"
                    style={{
                      left: start * DAY_WIDTH + 8,
                      width: Math.max(width * DAY_WIDTH - 16, 160),
                    }}
                  >
                    <div className="flex items-center justify-between gap-3 mb-2">
                      <span className="font-body-sm text-[11px] font-bold text-on-surface truncate group-hover:text-primary transition-colors">{campaign.name}</span>
                      <span className="font-display text-[10px] font-bold text-on-surface opacity-60 tabular-nums">{progress}%</span>
                    </div>
                    <div className="h-1 w-full bg-black/[0.04] rounded-full overflow-hidden">
                      <div className="h-full bg-black opacity-60 rounded-full transition-all duration-1000" style={{ width: `${progress}%` }} />
                    </div>
                  </button>
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}

