"use client";

import React from "react";
import { LucideIcon } from "lucide-react";

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: "primary" | "secondary" | "ghost" | "danger" | "soft";
  size?: "sm" | "md" | "lg" | "icon";
  icon?: LucideIcon;
  iconPosition?: "left" | "right";
  isLoading?: boolean;
}

export default function Button({
  children,
  variant = "primary",
  size = "md",
  icon: Icon,
  iconPosition = "left",
  isLoading,
  className = "",
  style,
  ...props
}: ButtonProps) {
  const baseStyles = "inline-flex items-center justify-center gap-2 rounded-[6px] font-semibold transition-all duration-200 active:scale-[0.98] disabled:opacity-50 disabled:pointer-events-none";

  const variants = {
    primary: "bg-primary text-on-primary hover:shadow-[0_4px_12px_rgba(0,0,0,0.1)] hover:-translate-y-px active:translate-y-0",
    secondary: "bg-black/[0.04] text-on-surface hover:bg-black/[0.07] border border-black/[0.06]",
    ghost: "bg-transparent text-on-surface-variant hover:bg-black/[0.04] hover:text-on-surface",
    danger: "bg-red-500/10 text-red-600 hover:bg-red-500 hover:text-white",
    soft: "bg-black/[0.02] text-on-surface-variant hover:bg-black/[0.04] hover:text-on-surface border border-black/[0.04]",
  };

  const sizes = {
    sm: "px-2.5 py-1.5 text-[10px] font-label-caps tracking-wider",
    md: "px-4 py-2 text-[12px] font-display",
    lg: "px-6 py-3 text-[14px] font-display",
    icon: "p-2",
  };

  return (
    <button
      className={`${baseStyles} ${variants[variant]} ${sizes[size]} ${className}`}
      {...props}
    >
      {isLoading ? (
        <div className="w-4 h-4 border-2 border-current border-t-transparent rounded-full animate-spin" />
      ) : (
        <>
          {Icon && iconPosition === "left" && <Icon size={size === "sm" ? 12 : 14} strokeWidth={2.5} />}
          {children}
          {Icon && iconPosition === "right" && <Icon size={size === "sm" ? 12 : 14} strokeWidth={2.5} />}
        </>
      )}
    </button>
  );
}

"use client";

import React, { useState, useRef, useEffect } from "react";
import { ChevronDown } from "lucide-react";
import Button from "./Button";

interface DropdownOption {
  value: string;
  label: string;
  icon?: React.ReactNode;
}

interface DropdownProps {
  value: string;
  options: DropdownOption[];
  onChange: (value: string) => void;
  label?: string;
  className?: string;
  align?: "left" | "right";
}

export default function Dropdown({
  value,
  options,
  onChange,
  label,
  className = "",
  align = "left"
}: DropdownProps) {
  const [isOpen, setIsOpen] = useState(false);
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (containerRef.current && !containerRef.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const selectedOption = options.find(o => o.value === value);

  return (
    <div className={`relative ${className}`} ref={containerRef}>
      <button
        onClick={() => setIsOpen(!isOpen)}
        className="
          flex items-center gap-1.5 px-3 py-1.5 rounded-[6px] 
          bg-black/[0.02] border border-black/[0.06] hover:bg-black/[0.04] 
          transition-all font-display text-[12px] font-medium text-on-surface
        "
      >
        {label && <span className="opacity-40 font-label-caps text-[9px] font-bold uppercase tracking-wider mr-0.5">{label}:</span>}
        <span>{selectedOption?.label}</span>
        <ChevronDown 
          size={12} 
          className={`opacity-30 transition-transform duration-200 ${isOpen ? 'rotate-180' : ''}`} 
        />
      </button>

      {isOpen && (
        <div className={`
          absolute top-full mt-1.5 z-[100] py-1 rounded-[8px] shadow-xl bg-white 
          border border-black/[0.08] min-w-[160px] animate-in fade-in slide-in-from-top-1
          ${align === "right" ? "right-0" : "left-0"}
        `}>
          {options.map(option => (
            <button
              key={option.value}
              onClick={() => {
                onChange(option.value);
                setIsOpen(false);
              }}
              className={`
                w-full flex items-center justify-between px-3 py-2 
                hover:bg-black/[0.03] transition-colors text-left
                ${value === option.value ? 'bg-primary/[0.03]' : ''}
              `}
            >
              <div className="flex items-center gap-2">
                {option.icon && <span className="opacity-40">{option.icon}</span>}
                <span className={`font-display text-[12.5px] ${value === option.value ? 'font-semibold text-primary' : 'text-on-surface opacity-80'}`}>
                  {option.label}
                </span>
              </div>
              {value === option.value && <div className="w-1.5 h-1.5 rounded-full bg-primary" />}
            </button>
          ))}
        </div>
      )}
    </div>
  );
}

