    const d = new Date(currentDate);
    if (calView === "month") d.setMonth(d.getMonth() + dir);
    else d.setDate(d.getDate() + 7 * dir);
    setCurrentDate(d);
  };

  const monthLabel = currentDate.toLocaleString("default", { month: "long", year: "numeric" });

