    const matchesPlatform = platformFilter === "All" || p.platform === platformFilter;
    return matchesSearch && matchesStatus && matchesPlatform;
  });

  const openAdd = (date?: Date) => {
    setTargetDate(date ?? new Date());
    setIsAddOpen(true);
