                    <div className="flex items-center justify-between">
                       <div className="flex items-center gap-2.5">
                          <FileText size={14} className="text-on-surface-variant opacity-60" />
                          <span className="font-display text-[12px] text-on-surface-variant opacity-60">Assets</span>
                       </div>
                       <span className="font-display text-[12px] font-bold text-on-surface">{flow.relatedDocsCount || 0}</span>
                    </div>
                 </div>
              </section>

              {/* Action Sidebar */}
              <section className="pt-10 border-t border-black/[0.04] space-y-4">
                 <button 
                   onClick={() => onDelete(flow.id)}
                   className="w-full flex items-center justify-center gap-2 p-3 rounded-xl bg-red-50 text-red-500 font-display text-[11px] font-bold uppercase tracking-widest opacity-60 hover:opacity-100 transition-all"
                 >
                   <Trash2 size={14} />
                   Archive Flow
                 </button>
              </section>
           </div>
        </aside>
      </div>
    </div>
  );
}

"use client";

import React, { useState } from "react";
import { ChevronRight, Clock, Activity, MoreHorizontal, Layers, Trash2 } from "lucide-react";
import type { Flow } from "../types";
import { CATEGORY_COLORS } from "../types";
import SelectionBar from "../../components/shared/SelectionBar";
import ConfirmationModal from "../../components/shared/ConfirmationModal";
import Button from "../../components/ui/Button";

interface FlowListViewProps {
  flows: Flow[];
  onFlowClick: (flow: Flow) => void;
  onBulkDelete?: (ids: string[]) => void;
}

export default function FlowListView({ flows, onFlowClick, onBulkDelete }: FlowListViewProps) {
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);
  const [flowToDelete, setFlowToDelete] = useState<string | null>(null);

  const toggleAll = () => {
    if (selectedIds.size === flows.length) {
      setSelectedIds(new Set());
    } else {
      setSelectedIds(new Set(flows.map(f => f.id)));
    }
  };

  const toggleOne = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    const next = new Set(selectedIds);
    if (next.has(id)) next.delete(id);
    else next.add(id);
    setSelectedIds(next);
  };

  const handleDeleteOne = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    setFlowToDelete(id);
    setIsDeleteModalOpen(true);
  };

  const handleConfirmDelete = () => {
    const ids = flowToDelete ? [flowToDelete] : Array.from(selectedIds);
    onBulkDelete?.(ids);
    setSelectedIds(new Set());
    setFlowToDelete(null);
    setIsDeleteModalOpen(false);
  };

  return (
    <div className="w-full animate-fade-in relative">
      <div className="min-w-full inline-block align-middle">
        <div className="border border-black/[0.06] rounded-2xl overflow-hidden bg-white">
          <table className="min-w-full border-separate border-spacing-0">
            <thead>
              <tr className="bg-[#fbf5f5] border-b border-black/[0.05]">
                <th className="px-6 py-4 text-left font-display text-[10px] font-bold text-on-surface-variant opacity-60 uppercase tracking-[0.2em]">Process Name</th>
                <th className="px-6 py-4 text-left font-display text-[10px] font-bold text-on-surface-variant opacity-60 uppercase tracking-[0.2em]">Completion</th>
                <th className="px-6 py-4 text-left font-display text-[10px] font-bold text-on-surface-variant opacity-60 uppercase tracking-[0.2em]">Stages</th>
                <th className="px-6 py-4 text-left font-display text-[10px] font-bold text-on-surface-variant opacity-60 uppercase tracking-[0.2em]">Updated</th>
                <th className="px-6 py-4 text-right font-display text-[10px] font-bold text-on-surface-variant opacity-60 uppercase tracking-[0.2em]">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-black/[0.04]">
              {flows.map((flow) => {
                const updatedDate = new Date(flow.updated).toLocaleDateString("en-US", { month: "short", day: "numeric" });
                const isSelected = selectedIds.has(flow.id);
                const progress = flow.progress;

                return (
                  <tr 
                    key={flow.id} 
                    onClick={() => onFlowClick(flow)}
                    className={`group hover:bg-black/[0.015] cursor-pointer transition-colors ${isSelected ? "bg-primary/[0.02]" : ""}`}
                  >
                    <td className="px-6 py-5 whitespace-nowrap">
                      <div className="flex items-center gap-4">
                         <div className="w-9 h-9 rounded-xl bg-black/[0.03] flex items-center justify-center text-on-surface-variant opacity-60 group-hover:bg-primary/5 group-hover:text-primary group-hover:opacity-100 transition-all">
                            <Layers size={15} />
                         </div>
                         <div>
                            <div className="flex items-center gap-2 mb-0.5">
                               <span className={`px-1.5 py-0.5 rounded font-display text-[8px] font-bold uppercase tracking-wider ${CATEGORY_COLORS[flow.category] || "text-slate-500 bg-slate-50"}`}>
                                 {flow.category}
                               </span>
                               {flow.status === "Active" && <span className="w-1 h-1 rounded-full bg-emerald-500" />}
                            </div>
                            <span className="font-display text-[14px] font-semibold text-on-surface tracking-tight transition-colors opacity-90 group-hover:text-primary">{flow.name}</span>
                         </div>
                      </div>
                    </td>
                    <td className="px-6 py-5 whitespace-nowrap">
                      <div className="flex items-center gap-3 w-32">
                         <div className="flex-1 h-1 bg-black/[0.05] rounded-full overflow-hidden">
                            <div className="h-full bg-primary/60 transition-all duration-700" style={{ width: `${progress}%` }} />
                         </div>
                         <span className="font-display text-[11px] font-bold text-on-surface-variant opacity-60 leading-none">{progress}%</span>
                      </div>
                    </td>
                    <td className="px-6 py-5 whitespace-nowrap">
                       <div className="flex items-center gap-2 text-on-surface opacity-60 font-display">
                          <Activity size={11} className="opacity-60" />
                          <span className="font-display text-[12px] font-bold">{flow.stages.length} <span className="opacity-60 font-medium">Stages</span></span>
                       </div>
                    </td>
                    <td className="px-6 py-5 whitespace-nowrap">
                       <div className="flex items-center gap-2 text-on-surface-variant opacity-60 font-display">
                          <Clock size={11} className="opacity-60" />
                          <span className="font-display text-[12px] font-medium">{updatedDate}</span>
                       </div>
                    </td>
                    <td className="px-6 py-5 whitespace-nowrap text-right">
                       <div className="flex items-center justify-end gap-1 opacity-0 group-hover:opacity-100 transition-all">
                          <Button 
                            variant="ghost" 
                            size="icon" 
                            className="h-8 w-8 text-on-surface-variant opacity-60 hover:text-red-500 hover:opacity-100 hover:bg-red-50"
                            onClick={(e) => handleDeleteOne(e, flow.id)}
                          >
                            <Trash2 size={14} />
                          </Button>
                          <Button variant="ghost" size="icon" className="h-8 w-8 text-on-surface-variant opacity-60">
                            <MoreHorizontal size={14} />
                          </Button>
                          <ChevronRight size={14} className="text-on-surface-variant opacity-60 ml-1" />
                       </div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>

      <SelectionBar 
        count={selectedIds.size}
        onClear={() => setSelectedIds(new Set())}
        onDelete={() => setIsDeleteModalOpen(true)}
        label="flows"
      />

      <ConfirmationModal 
        isOpen={isDeleteModalOpen}
        onClose={() => {
          setIsDeleteModalOpen(false);
          setFlowToDelete(null);
        }}
        onConfirm={handleConfirmDelete}
        title={flowToDelete ? "Delete Flow" : "Delete Selected Flows"}
        description={flowToDelete ? "Are you sure you want to delete this operational flow? All associated stages and history data will be permanently removed." : `Are you sure you want to delete ${selectedIds.size} selected flows? This action cannot be undone.`}
      />
    </div>
  );
}

"use client";

import { useState } from "react";
import { X, Plus, Trash2, CheckCircle2, Calendar, Target, AlignLeft, ListChecks } from "lucide-react";
import type { Goal, Milestone, GoalStatus, Priority } from "../types";

interface CreateGoalModalProps {
  onClose: () => void;
  onCreate?: (goal: Goal) => void;
}

function genId(prefix = "id") {
  return `${prefix}-${Date.now()}-${Math.random().toString(36).slice(2, 6)}`;
}

export default function CreateGoalModal({ onClose, onCreate }: CreateGoalModalProps) {
  const [title, setTitle] = useState("");
  const [description, setDescription] = useState("");
  const [targetDate, setTargetDate] = useState("");
  const [priority, setPriority] = useState<Priority>("medium");
  const [tempMilestones, setTempMilestones] = useState<{ id: string; title: string; date: string }[]>([
    { id: genId("ms"), title: "", date: "" }
  ]);
  const [error, setError] = useState("");

  function addMilestone() {
    setTempMilestones(prev => [...prev, { id: genId("ms"), title: "", date: "" }]);
  }

  function updateMilestone(id: string, updates: Partial<{ title: string; date: string }>) {
    setTempMilestones(prev => prev.map(m => m.id === id ? { ...m, ...updates } : m));
  }

  function removeMilestone(id: string) {
    if (tempMilestones.length <= 1) return;
    setTempMilestones(prev => prev.filter(m => m.id !== id));
  }

  function handleSubmit() {
    if (!title.trim()) { setError("Goal title is required."); return; }
    if (!targetDate) { setError("Target date is required."); return; }

    const now = new Date().toISOString().slice(0, 10);
    const newGoal: Goal = {
      id: genId("goal"),
      title: title.trim(),
      description: description.trim(),
      status: "on-track",
      priority,
      ownerId: "me",
      collaboratorIds: [],
      startDate: now,
      targetDate,
      progress: 0,
      keyResults: [],
      milestones: tempMilestones
        .filter(m => m.title.trim() !== "")
        .map(m => ({ id: m.id, title: m.title, date: m.date || targetDate, completed: false })),
      linkedItems: [],
      activities: []
    };

    if (onCreate) onCreate(newGoal);
    onClose();
  }

  return (
    <>
      <div className="fixed inset-0 z-[60] bg-black/30 backdrop-blur-[4px] animate-in fade-in duration-300" onClick={onClose} />

      <div
        className="fixed z-[70] top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-full flex flex-col animate-in zoom-in-95 duration-300 shadow-2xl"
        style={{
          maxWidth: 640,
          maxHeight: "85vh",
          background: "var(--color-background)",
          borderRadius: 8,
          overflow: "hidden",
        }}
      >
        {/* Header */}
        <div className="flex items-center justify-between px-8 py-6 border-b border-black/[0.06] bg-white">
          <div className="flex items-center gap-4">
             <div className="w-10 h-10 rounded-xl bg-primary flex items-center justify-center text-white shadow-lg shadow-primary/20">
                <Target size={20} />
             </div>
             <div>
                <h2 className="font-display text-[17px] font-semibold text-on-surface tracking-tight">New Operational Goal</h2>
                <p className="font-body-sm text-[12px] text-on-surface-variant opacity-40">Define a clear target and track its progress</p>
             </div>
          </div>
          <button onClick={onClose} className="p-2 rounded-lg hover:bg-black/5 transition-colors">
            <X size={18} className="text-on-surface-variant opacity-40" />
          </button>
        </div>

        {/* Body */}
        <div className="flex-1 overflow-y-auto px-8 py-8 space-y-10 custom-scrollbar">
          {/* Identity Section */}
          <section className="space-y-6">
            <div className="space-y-2">
              <label className="font-label-caps text-[9px] font-bold text-on-surface-variant opacity-40 uppercase tracking-widest ml-1">Goal Title</label>
              <input
                autoFocus
                value={title}
                onChange={e => { setTitle(e.target.value); setError(""); }}
                placeholder="e.g. Q3 Sales Expansion"
                className="w-full px-4 py-3.5 rounded-lg border border-black/[0.08] bg-white font-display text-[14px] font-medium outline-none focus:border-primary/40 transition-all text-on-surface"
              />
            </div>

            <div className="grid grid-cols-2 gap-6">
               <div className="space-y-2">
                  <label className="font-label-caps text-[9px] font-bold text-on-surface-variant opacity-40 uppercase tracking-widest ml-1">Deadline</label>
                  <div className="relative">
                     <Calendar size={14} className="absolute left-4 top-1/2 -translate-y-1/2 text-on-surface-variant opacity-30" />
                     <input
                       type="date"
                       value={targetDate}
                       onChange={e => setTargetDate(e.target.value)}
                       className="w-full pl-10 pr-4 py-3.5 rounded-lg border border-black/[0.08] bg-white font-display text-[14px] outline-none text-on-surface"
                     />
                  </div>
               </div>
               <div className="space-y-2">
                  <label className="font-label-caps text-[9px] font-bold text-on-surface-variant opacity-40 uppercase tracking-widest ml-1">Priority</label>
                  <select
                    value={priority}
                    onChange={e => setPriority(e.target.value as Priority)}
                    className="w-full px-4 py-3.5 rounded-lg border border-black/[0.08] bg-white font-display text-[14px] outline-none appearance-none cursor-pointer text-on-surface"
                  >
                    <option value="low">Low</option>
                    <option value="medium">Medium</option>
                    <option value="high">High</option>
                    <option value="critical">Critical</option>
                  </select>
               </div>
            </div>

            <div className="space-y-2">
              <label className="font-label-caps text-[9px] font-bold text-on-surface-variant opacity-40 uppercase tracking-widest ml-1">Description</label>
              <textarea
                value={description}
                onChange={e => setDescription(e.target.value)}
                placeholder="Briefly describe the objective and context..."
                rows={2}
                className="w-full px-4 py-3.5 rounded-lg border border-black/[0.08] bg-white font-display text-[14px] outline-none resize-none focus:border-primary/40 transition-all text-on-surface"
              />
            </div>
          </section>

          {/* Milestones Section */}
          <section className="space-y-6 pt-10 border-t border-black/[0.04]">
            <div className="flex items-center justify-between mb-4">
               <h3 className="font-label-caps text-[10px] font-bold text-on-surface-variant opacity-30 uppercase tracking-[0.2em] ml-1">Key Milestones</h3>
               <button onClick={addMilestone} className="flex items-center gap-2 px-3 py-1.5 rounded-lg bg-black/[0.04] hover:bg-black/[0.08] text-on-surface-variant opacity-60 hover:opacity-100 transition-all">
                  <Plus size={14} />
                  <span className="font-label-caps text-[9px] font-bold uppercase">Add Milestone</span>
               </button>
            </div>

            <div className="space-y-4">
               {tempMilestones.map((m, idx) => (
                 <div key={m.id} className="group flex items-start gap-4 bg-black/[0.01] border border-black/[0.05] rounded-xl p-5 transition-all hover:bg-white hover:shadow-lg">
                    <div className="w-6 h-6 rounded-full bg-black/[0.06] flex items-center justify-center font-display text-[11px] font-bold text-on-surface-variant opacity-40 mt-1 shrink-0">
                       {idx + 1}
                    </div>
                    <div className="flex-1 grid grid-cols-5 gap-4">
                       <input 
                         value={m.title}
                         onChange={e => updateMilestone(m.id, { title: e.target.value })}
                         placeholder="Milestone title..."
                         className="col-span-3 bg-transparent font-display text-[14px] font-semibold text-on-surface outline-none border-b border-transparent focus:border-primary/20 pb-0.5 transition-all"
                       />
                       <input 
                         type="date"
                         value={m.date}
                         onChange={e => updateMilestone(m.id, { date: e.target.value })}
                         className="col-span-2 bg-transparent font-body-sm text-[12px] text-on-surface-variant outline-none border-b border-black/[0.03] focus:border-primary/20 transition-all"
                       />
                    </div>
                    <button onClick={() => removeMilestone(m.id)} className="p-1.5 rounded-lg text-red-500 opacity-0 group-hover:opacity-40 hover:opacity-100 transition-opacity mt-1">
                       <Trash2 size={14} />
                    </button>
                 </div>
               ))}
            </div>
          </section>

          {error && <div className="p-4 rounded-lg bg-red-50 border border-red-100 text-red-600 font-body-sm text-[12px] flex items-center gap-2"><X size={14} /> {error}</div>}
        </div>

        {/* Footer */}
        <div className="px-8 py-5 border-t border-black/[0.06] bg-black/[0.01] flex items-center justify-end gap-3">
           <button onClick={onClose} className="px-5 py-2.5 rounded-lg font-label-caps text-[10px] font-bold text-on-surface-variant opacity-40 hover:opacity-100 transition-all uppercase tracking-widest">Cancel</button>
           <button onClick={handleSubmit} className="px-6 py-2.5 rounded-lg bg-primary text-on-primary font-label-caps text-[10px] font-bold uppercase tracking-widest shadow-lg shadow-primary/20 hover:shadow-xl hover:-translate-y-px transition-all active:scale-[0.98]">Set Goal</button>
        </div>
      </div>
    </>
  );
}

"use client";

import { useState } from "react";
import { X, Target, CheckCircle2, Circle, Clock, MoreHorizontal, Trash2, Edit3, Save, Plus, FileText, MessageSquare, TrendingUp, AlertCircle } from "lucide-react";
import type { Goal, Milestone } from "../types";

interface GoalDetailProps {
  goal: Goal;
  onClose: () => void;
  onUpdate: (updated: Goal) => void;
  onDelete: (id: string) => void;
}

export default function GoalDetail({ goal: initialGoal, onClose, onUpdate, onDelete }: GoalDetailProps) {
  const [goal, setFlow] = useState<Goal>(initialGoal);
  const [isEditing, setIsEditing] = useState(false);

  function handleUpdate(updates: Partial<Goal>) {
    const next = { ...goal, ...updates };
    setFlow(next);
    onUpdate(next);
  }

  function toggleMilestone(milestoneId: string) {
    const nextMilestones = goal.milestones.map(m =>
      m.id === milestoneId ? { ...m, completed: !m.completed } : m
    );

    // Calculate new progress based on milestones
    const completedCount = nextMilestones.filter(m => m.completed).length;
    const progress = nextMilestones.length === 0 ? 0 : Math.round((completedCount / nextMilestones.length) * 100);

    handleUpdate({ milestones: nextMilestones, progress });
  }

  return (
    <div className="flex-1 flex flex-col h-full bg-background animate-fade-in overflow-hidden">
      {/* Header */}
      <header className="px-8 py-5 border-b border-black/[0.05] flex items-center justify-between bg-white/60 backdrop-blur-md sticky top-0 z-10">
        <div className="flex items-center gap-6">
          <button
            onClick={onClose}
            className="p-2 rounded-lg hover:bg-black/5 transition-all text-on-surface-variant opacity-40 hover:opacity-100"
          >
            <X size={18} />
          </button>
          <div>
            <div className="flex items-center gap-2 mb-1">
              <span className="font-label-caps text-[9px] font-bold text-primary uppercase tracking-widest">Operational Goal</span>
              <span className="w-1 h-1 rounded-full bg-black/10" />
              <span className="font-label-caps text-[9px] font-semibold text-on-surface-variant opacity-30 uppercase tracking-widest">Target: {goal.targetDate}</span>
            </div>
            {isEditing ? (
              <input
                value={goal.title}
                onChange={e => handleUpdate({ title: e.target.value })}
                className="font-display text-[18px] font-semibold text-on-surface bg-transparent outline-none border-b border-primary/20 pb-0.5"
                autoFocus
              />
            ) : (
              <h1 className="font-display text-[18px] font-semibold text-on-surface tracking-tight">{goal.title}</h1>
            )}
          </div>
        </div>

        <div className="flex items-center gap-3">
          <button
            onClick={() => setIsEditing(!isEditing)}
            className="flex items-center gap-2 px-4 py-2 rounded-lg hover:bg-black/5 text-on-surface-variant opacity-60 hover:opacity-100 transition-all font-label-caps text-[10px] font-bold uppercase tracking-widest"
          >
            {isEditing ? <><Save size={14} /> Save Changes</> : <><Edit3 size={14} /> Edit Goal</>}
          </button>
          <div className="w-px h-4 bg-black/[0.1]" />
          <button
            onClick={() => onDelete(goal.id)}
            className="p-2 rounded-lg hover:bg-red-50 text-red-500 opacity-40 hover:opacity-100 transition-all"
          >
            <Trash2 size={16} />
          </button>
        </div>
      </header>

      {/* Main Content Split */}
      <div className="flex-1 flex overflow-hidden">
        {/* Left Content */}
        <div className="flex-1 overflow-y-auto p-12 border-r border-black/[0.04]">
          <div className="max-w-3xl mx-auto">
            {/* Overview */}
            <div className="mb-14">
              <h2 className="font-label-caps text-[10px] font-bold text-on-surface-variant opacity-30 uppercase tracking-[0.2em] mb-4">Goal Context</h2>
              {isEditing ? (
                <textarea
                  value={goal.description}
                  onChange={e => handleUpdate({ description: e.target.value })}
                  className="w-full font-body-md text-[14px] text-on-surface bg-black/[0.02] rounded-lg p-4 outline-none focus:bg-white border border-transparent focus:border-primary/10 transition-all"
                  rows={3}
                />
              ) : (
                <p className="font-body-md text-[14px] text-on-surface opacity-80 leading-relaxed">{goal.description || "No context provided for this goal."}</p>
              )}
            </div>

            {/* Milestones */}
            <div className="space-y-6">
              <div className="flex items-center justify-between mb-8">
                <h2 className="font-label-caps text-[10px] font-bold text-on-surface-variant opacity-30 uppercase tracking-[0.2em]">Execution Milestones</h2>
                <button className="flex items-center gap-2 px-3 py-1.5 rounded-lg bg-primary/5 text-primary font-label-caps text-[9px] font-bold uppercase">
                  <Plus size={12} /> Add Milestone
                </button>
              </div>

              <div className="space-y-4">
                {goal.milestones.map((m, idx) => {
                  const isLast = idx === goal.milestones.length - 1;
                  return (
                    <div key={m.id} className="relative flex gap-6 group">
                      {!isLast && (
                        <div className="absolute left-[13.5px] top-8 bottom-[-16px] w-[1px] bg-black/[0.05]" />
                      )}

                      <div className="shrink-0 pt-1.5 relative z-10">
                        <button
                          onClick={() => toggleMilestone(m.id)}
                          className={`w-7 h-7 rounded-lg flex items-center justify-center transition-all ${m.completed ? 'bg-emerald-500 text-white shadow-lg shadow-emerald-500/20' : 'bg-white border border-black/10 text-black/20 hover:border-primary hover:text-primary'}`}
                        >
                          {m.completed ? <CheckCircle2 size={16} /> : <div className="w-1.5 h-1.5 rounded-full bg-current" />}
                        </button>
                      </div>

                      <div className="flex-1 pb-8">
                        <div className={`p-5 rounded-xl border border-black/[0.04] transition-all group-hover:bg-white group-hover:border-black/[0.08] ${m.completed ? 'bg-black/[0.01] opacity-60' : 'bg-white/40'}`}>
                          <div className="flex items-center justify-between mb-2">
                            <h3 className={`font-display text-[14px] font-semibold ${m.completed ? 'line-through' : 'text-on-surface'}`}>{m.title}</h3>
                            <span className="font-label-caps text-[8px] font-bold text-on-surface-variant opacity-30 uppercase tracking-widest">{m.date}</span>
                          </div>
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          </div>
        </div>

        {/* Right Sidebar */}
        <aside className="w-[340px] bg-white/10 backdrop-blur-xl flex flex-col overflow-y-auto">
          <div className="p-8 space-y-12">
            {/* Progress Radial */}
            <section>
              <h4 className="font-label-caps text-[10px] font-bold text-on-surface-variant opacity-30 uppercase tracking-[0.2em] mb-8">Goal Progress</h4>
              <div className="relative w-36 h-36 mx-auto mb-8">
