                               <button className="w-full py-2 rounded-lg border border-black/[0.08] bg-white font-label-caps text-[8.5px] font-bold tracking-widest text-on-surface-variant opacity-80 hover:opacity-100 transition-all">
                                  PRINT BARCODES
                               </button>
