      />

      {/* ── Main Workspace Area ── */}
      <main className="flex-1 overflow-y-auto bg-background">
        <div className="animate-fade-in">
          <ProductTable />
        </div>
      </main>

      {isAddModalOpen && (
        <AddProductModal onClose={() => setIsAddModalOpen(false)} />
      )}
    </div>
  );
}

export default function InventoryPage() {
  return (
    <InventoryProvider>
      <InventoryContent />
    </InventoryProvider>
  );
}

