// Components
import MembersDirectory from "./components/MembersDirectory";
import RolesPermissions from "./components/RolesPermissions";
import ActivityAuditLog from "./components/ActivityAuditLog";
import InviteModal from "./components/InviteModal";
import MemberDrawer from "./components/MemberDrawer";

// Shared UI
import ModuleHeader from "../components/shared/ModuleHeader";
import ModuleTabs from "../components/shared/ModuleTabs";
import SearchInput from "../components/shared/SearchInput";
import Button from "../components/ui/Button";

type Tab = "directory" | "roles" | "activity";

export default function MembersPage() {
  const { members, currentUserRole, tenantCode } = useMembers();
  const canInvite = currentUserRole === "Owner" || currentUserRole === "Admin";

  const [activeTab, setActiveTab] = useState<Tab>("directory");
  const [searchQuery, setSearchQuery] = useState("");
  const [showInviteModal, setShowInviteModal] = useState(false);
  const [selectedMemberId, setSelectedMemberId] = useState<string | null>(null);
  const [copiedCode, setCopiedCode] = useState(false);

  const copyInviteCode = async () => {
    if (!tenantCode) return;
    let copied = false;

    try {
      if (navigator.clipboard?.writeText) {
        await navigator.clipboard.writeText(tenantCode);
        copied = true;
      }
    } catch {
      copied = false;
    }

    if (!copied) {
      const el = document.createElement("textarea");
      el.value = tenantCode;
      el.style.position = "fixed";
      el.style.opacity = "0";
      document.body.appendChild(el);
      el.focus();
      el.select();
      copied = document.execCommand("copy");
      document.body.removeChild(el);
    }

    setCopiedCode(copied);
    if (copied) setTimeout(() => setCopiedCode(false), 2000);
  };

  const tabs = [
    { id: "directory", label: "Directory", icon: Users },
    { id: "roles", label: "Roles & Permissions", icon: Shield },
    { id: "activity", label: "Audit Log", icon: Clock },
  ];

  return (
    <div className="flex flex-col h-full overflow-hidden bg-background">
      {/* ── Module Header ── */}
      <ModuleHeader
        title="Members"
        count={members.length}
        rightContent={(
          <>
            <SearchInput
              value={searchQuery}
              onChange={setSearchQuery}
              placeholder="Search members..."
              width={200}
            />
            {canInvite && (
              <>
                <Button
                  variant="primary"
                  size="sm"
                  icon={Plus}
                  onClick={() => setShowInviteModal(true)}
                >
                  INVITE MEMBER
                </Button>
              </>
            )}
          </>
        )}
      />

      {/* ── Tabs ── */}
      <ModuleTabs
        tabs={tabs}
        activeTab={activeTab}
        onTabChange={(id) => setActiveTab(id as Tab)}
        background="bg-black/[0.01]"
      />

      {/* ── View Area ── */}
      <div className="flex-1 overflow-y-auto">
        {activeTab === "directory" && <MembersDirectory searchQuery={searchQuery} onSelectMember={setSelectedMemberId} />}
        {activeTab === "roles" && <RolesPermissions />}
        {activeTab === "activity" && <ActivityAuditLog />}
      </div>


      {/* ── Modals & Drawers ── */}
      {showInviteModal && canInvite && <InviteModal onClose={() => setShowInviteModal(false)} />}
      {selectedMemberId && <MemberDrawer memberId={selectedMemberId} onClose={() => setSelectedMemberId(null)} />}
    </div>
  );
}

"use client";

import React, { createContext, useContext, useState, useMemo, useEffect } from "react";
import { Report, ReportType, ReportStatus } from "../types";
import { createReport, listReports, updateReport as saveReport } from "@/lib/client/services/report.service";

interface ReportsContextType {
  reports: Report[];
  addReport: (report: Omit<Report, "id" | "createdAt" | "updatedAt" | "status">) => void;
  generateReport: (id: string) => void;
  archiveReport: (id: string) => void;
  searchQuery: string;
  setSearchQuery: (query: string) => void;
  selectedType: "All" | ReportType;
  setSelectedType: (type: "All" | ReportType) => void;
}

const ReportsContext = createContext<ReportsContextType | undefined>(undefined);

export function ReportsProvider({ children }: { children: React.ReactNode }) {
  const [reports, setReports] = useState<Report[]>([]);
  const [searchQuery, setSearchQuery] = useState("");
  const [selectedType, setSelectedType] = useState<"All" | ReportType>("All");

  useEffect(() => {
    let cancelled = false;

    async function load() {
      try {
        const items = await listReports<Report>();
        if (!cancelled) setReports(items);
      } catch (err) {
        console.error("Failed to load reports:", err);
      }
    }

    load();
    return () => {
      cancelled = true;
    };
  }, []);

  const addReport = (data: Omit<Report, "id" | "createdAt" | "updatedAt" | "status">) => {
    const newReport: Report = {
      ...data,
      id: "r" + Math.random().toString(36).substr(2, 9),
      status: "Ready",
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString()
    };
    createReport<Report>(newReport)
      .then((created) => setReports(prev => [created, ...prev]))
      .catch((err) => console.error("Failed to create report:", err));
  };

  const generateReport = (id: string) => {
    setReports(prev => prev.map(r => {
      if (r.id !== id) return r;
      const updated: Report = { ...r, status: "Ready", lastGeneratedAt: new Date().toISOString(), updatedAt: new Date().toISOString() };
      const recordId = (r as { recordId?: string }).recordId ?? r.id;
      saveReport<Report>(recordId, updated).catch((err) => {
        console.error("Failed to generate report:", err);
      });
      return updated;
    }));
  };

  const archiveReport = (id: string) => {
    setReports(prev => prev.map(r => {
      if (r.id !== id) return r;
      const updated: Report = { ...r, status: "Archived", updatedAt: new Date().toISOString() };
      const recordId = (r as { recordId?: string }).recordId ?? r.id;
      saveReport<Report>(recordId, updated).catch((err) => {
        console.error("Failed to archive report:", err);
      });
      return updated;
    }));
  };

  const filteredReports = useMemo(() => {
    return reports.filter(r => {
      const matchesSearch = r.title.toLowerCase().includes(searchQuery.toLowerCase()) || 
                            r.description.toLowerCase().includes(searchQuery.toLowerCase());
      const matchesType = selectedType === "All" || r.type === selectedType;
      return matchesSearch && matchesType;
    });
  }, [reports, searchQuery, selectedType]);

  const value = {
    reports: filteredReports,
    addReport,
    generateReport,
    archiveReport,
    searchQuery,
    setSearchQuery,
    selectedType,
    setSelectedType
  };

  return <ReportsContext.Provider value={value}>{children}</ReportsContext.Provider>;
}

export function useReports() {
  const context = useContext(ReportsContext);
  if (!context) throw new Error("useReports must be used within ReportsProvider");
  return context;
}

