   s === "Active" ? "bg-black" : s === "Inactive" ? "bg-black/60" : "bg-black/60";

const statusLabel = (s: ChannelStatus) =>
   s === "Active" ? "bg-black text-white" : "bg-black/[0.05] text-black/100";

